onClick:
{{
  (() => {
    // Executa a query injetando os parâmetros do Autista
    Query_Atualizar_Autista.run({
      data_e_hora_denuncia_Autista: Input_data_e_hora_denuncia.text,
      Telefone_Autista: Telefone_Autista.text,
      Email_Autista: Email_Autista.text,
      Nome_Denunciante_Autista: Nome_Denunciante_Autista.text,
      Nome_Agressor_Autista: Nome_Agressor_Autista.text,
      Nome_Testemunha_Autista: Nome_Testemunha_Autista.text,
      Localizacao_Autista: Localizacao_Autista.text,
      Resposta_Denunciante_Autista: Resposta_Denunciante_Autista.text,
      data_reg_Autista: data_reg_Autista.text,
      hora_reg_Autista: hora_reg_Autista.text,
      classificacao_Autista: classificacao_Autista.text,
      Descricao_Autista: Descricao_Autista.text,
      Num_Denuncia_Autista: select_altera_cad_Autista.selectedOptionValue
    })
    .then(() => {
      // Recarrega a query/tabela principal do Autista para atualizar a tela
      Tabela_Cad_Autista.run(); 

      // Alerta de sucesso
      showAlert('Alterações salvas com sucesso!', 'success');

      // Lista de campos do Autista para limpar
      const camposDoModal = [
        "Input_data_e_hora_denuncia",
        "Telefone_Autista",
        "Email_Autista",
        "Nome_Denunciante_Autista",
        "Nome_Agressor_Autista",
        "Nome_Testemunha_Autista",
        "Localizacao_Autista",
        "Resposta_Denunciante_Autista",
        "data_reg_Autista",
        "hora_reg_Autista",
        "classificacao_Autista",
        "Descricao_Autista"
      ];

      // Executa a limpeza individual dos componentes
      camposDoModal.forEach(async (campo) => {
        await resetWidget(campo, true);
      });

      // Fecha o modal do Autista automaticamente
      closeModal("Modal_Editar_Cad_Autista");
    })
    .catch((err) => {
      showAlert('Erro ao processar atualizações: ' + err.message, 'error');
    });
  })()
}}
